  @doc """
  Build a ProductCollection JSON-LD map.

  ## Fields

  - `:includes_object` - This links to a node or nodes indicating the exact quantity of the products included in an `SEO.JSONLD.Offer` or `SEO.JSONLD.ProductCollection`.

  ### Inherited properties

  Additional properties are available through the inheritance chain. See
  each ancestor's docs for its properties:

  - `SEO.JSONLD.Collection`
  - `SEO.JSONLD.Product`
  - `SEO.JSONLD.CreativeWork`
  - `SEO.JSONLD.Thing`
  """
  @spec build(attrs()) :: t()
  def build(attrs) do
    attrs
    |> Enum.into(%{})
    |> SEO.Utils.build_convert_enums(@enum_fields)
    |> SEO.Utils.build_coerce_structs()
    |> SEO.Utils.build_camelize_keys(@key_map)
    |> Map.put_new("@context", "https://schema.org")
    |> Map.put_new("@type", "ProductCollection")
  end
end
